raw:
{
  "qa_list": [
    {
      "q": "추론형 AI 데이터 품질 관리가 대상으로 하는 범위와 접근 방식의 특징은 무엇입니까?",
      "a": "추론형 AI 데이터 품질 관리는 AI 모델의 데이터 생애 주기(lifecycle)를 대상으로 하며, 세밀한 품질 중심 접근을 강조합니다.",
      "intent": "fact",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '추론형 AI 데이터 품질 관리는 AI 모델의 데이터 생애 주기(lifecycle)를 대상으로 하며 세밀한 품질 중심 접근을 강조합니다.'에서 직접 추출 가능",
        "2) 질문 구성 방식 — 단순 명칭 조회가 아닌, 관리 대상 범위와 접근 방식의 특징이라는 두 가지 속성을 동일한 fact 차원 내에서 묻는 단일 차원 복수 항목 질문으로 구성"
      ],
      "answerable": true
    },
    {
      "q": "추론형 AI 데이터 생애주기를 구성하는 단계들은 순서대로 무엇입니까?",
      "a": "추론형 AI 데이터 생애주기는 생성(Generation), 검증(Verification), 정제(Cleansing), 평가(Evaluation), 재구성(Reconstruction)의 5단계로 구성됩니다.",
      "intent": "list",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '추론형 AI 데이터 생애주기는 생성(Generation) ⇨ 검증(Verification) ⇨ 정제(Cleansing) ⇨ 평가(Evaluation) ⇨ 재구성(Reconstruction)의 단계를 거칩니다.'에서 5개 항목 전체 직접 추출",
        "2) 질문 구성 방식 — 순서가 명시된 열거 구조이므로 list 유형으로 분류하며, 5개 항목 모두를 순서에 맞게 포함하는 완전 답변으로 구성"
      ],
      "answerable": true
    },
    {
      "q": "추론형 AI 데이터 생애주기에서 정제(Cleansing) 단계는 전체 흐름 중 어느 위치에 해당하며, 직전 및 직후 단계는 각각 무엇입니까?",
      "a": "정제(Cleansing) 단계는 추론형 AI 데이터 생애주기의 5단계 중 세 번째 단계에 해당합니다. 직전 단계는 검증(Verification)이며, 직후 단계는 평가(Evaluation)입니다.",
      "intent": "how",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '생성(Generation) ⇨ 검증(Verification) ⇨ 정제(Cleansing) ⇨ 평가(Evaluation) ⇨ 재구성(Reconstruction)의 단계를 거칩니다.'에서 단계별 순서 관계가 명시되어 있으므로 위치 특정 가능",
        "2) 질문 구성 방식 — 특정 단계의 생애주기 내 위치와 인접 단계를 묻는 how 유형으로 구성하며, 컨텍스트에 명시된 순서(⇨) 기호를 근거로 직전·직후 단계를 서술"
      ],
      "answerable": true
    }
  ]
}

{
  "qa_list": [
    {
      "q": "불완전하거나 편향된 데이터가 AI 시스템에 미치는 영향은 무엇입니까?",
      "a": "불완전·편향 데이터는 추론 과정에서 논리적 왜곡(Logical Distortion)을 유발하며, 데이터 품질이 AI 시스템의 신뢰성과 안전성(Safety)을 직접적으로 좌우합니다. 구체적 사례로, 의료 AI 모델이 부정확한 임상 데이터를 학습한 경우 진단 오류(Misdiagnosis)나 치명적 오진(Fatal misjudgment)을 유발할 수 있습니다.",
      "intent": "fact",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '불완전·편향 데이터는 추론 과정에서 논리적 왜곡(Logical Distortion)을 유발하며, 데이터 품질이 AI 시스템의 신뢰성과 안전성(Safety)을 직접적으로 좌우합니다' 및 '의료 AI 모델이 부정확한 임상 데이터를 학습한 경우 진단 오류(Misdiagnosis)나 치명적 오진(Fatal misjudgment)을 유발할 수 있습니다'에서 직접 추출",
        "2) 질문 구성 방식 — 데이터 품질 문제가 AI 시스템에 미치는 구체적 영향(논리적 왜곡, 신뢰성·안전성 저하, 의료 오진)을 단일 fact 차원에서 복수 항목으로 묻는 구조로 설계"
      ],
      "answerable": true
    },
    {
      "q": "데이터의 다양성 및 공정성 부족이 초래하는 문제는 무엇입니까?",
      "a": "데이터의 다양성(Diversity) 및 공정성(Fairness) 부족 시 사회적 편향 재생산을 초래하고, 특정 집단에 불리한 의사결정으로 윤리적 신뢰가 저하되는 문제가 발생합니다.",
      "intent": "fact",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '데이터의 다양성(Diversity) 및 공정성(Fairness) 부족 시 사회적 편향 재생산을 초래하고 특정 집단에 불리한 의사결정으로 윤리적 신뢰 저하되는 문제가 발생합니다'에서 직접 추출",
        "2) 질문 구성 방식 — 공정성 부족이 초래하는 복수의 결과(사회적 편향 재생산, 특정 집단 불리한 의사결정, 윤리적 신뢰 저하)를 단일 fact 차원에서 묻는 구조로 설계"
      ],
      "answerable": true
    },
    {
      "q": "AI 데이터의 정확성 확보 측면과 공정성·윤리성 측면에서 각각 요구되는 대응 방향은 어떻게 구분됩니까?",
      "a": "정확성과 신뢰성 측면에서는 정확하고 신뢰성 있는 데이터 확보 및 검증 체계 강화가 요구됩니다. 공정성과 윤리성 측면에서는 데이터 수집·가공·검증 전 과정에서 윤리적 데이터 거버넌스(Ethical Data Governance)가 중요한 대응 방향으로 제시됩니다.",
      "intent": "comparison",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '정확하고 신뢰성 있는 데이터 확보 및 검증 체계 강화가 필요합니다'(정확성 측면)와 '데이터 수집·가공·검증 전 과정에서 윤리적 데이터 거버넌스(Ethical Data Governance)가 중요합니다'(공정성·윤리성 측면) 두 문장을 각각 매핑",
        "2) 질문 구성 방식 — 컨텍스트가 (정확성과 신뢰성), (공정성과 윤리성) 두 개의 독립 절로 구분되어 있으므로 비교 질문이 적절하며, 각 측면의 대응 방향이 모두 명시되어 있어 대칭 검증 통과"
      ],
      "answerable": true
    },
    {
      "q": "윤리적 데이터 거버넌스가 적용되어야 하는 데이터 처리 과정의 범위는 어디까지입니까?",
      "a": "윤리적 데이터 거버넌스(Ethical Data Governance)는 데이터 수집, 가공, 검증의 전 과정에 걸쳐 적용되어야 합니다.",
      "intent": "condition",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '데이터 수집·가공·검증 전 과정에서 윤리적 데이터 거버넌스(Ethical Data Governance)가 중요합니다'에서 적용 범위를 직접 추출",
        "2) 질문 구성 방식 — 윤리적 데이터 거버넌스가 적용되어야 하는 범위 조건(수집·가공·검증 전 과정)을 condition 차원에서 묻는 구조로 설계"
      ],
      "answerable": true
    }
  ]
}

{
  "qa_list": [
    {
      "q": "추론형 AI 모델의 품질 관리 정책이 포함하는 복합 과제는 무엇입니까?",
      "a": "추론형 AI 모델의 품질 관리 정책은 단순 정제(cleaning)를 넘어 프라이버시 보호(GDPR 등 법규 준수), 데이터 스케일링 및 거버넌스 문제 해결, 품질 모니터링 자동화 등 복합 과제를 포함합니다.",
      "intent": "list",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '단순 정제(cleaning)를 넘어 프라이버시 보호(GDPR 등 법규 준수), 데이터 스케일링 및 거버넌스 문제 해결, 품질 모니터링 자동화 등 복합 과제를 포함합니다'에서 열거 항목 직접 추출 가능",
        "2) 질문 구성 방식 — 복수 항목(3가지)이 명시적으로 열거되어 있으므로 list 유형으로 구성하며, 모든 항목을 빠짐없이 포함"
      ],
      "answerable": true
    },
    {
      "q": "품질관리 활동이 AI 준비성(AI Readiness) 향상에 기여한다고 할 때, 추론형 AI 데이터가 단순한 학습 자원을 넘어 갖는 근본적 역할은 무엇입니까?",
      "a": "추론형 AI 데이터는 단순한 학습 자원이 아니라 AI의 사고 체계(Cognitive System)를 형성하는 근본적 요소입니다. 아울러 품질관리 활동은 AI 준비성(AI Readiness) 향상 및 지속가능한 AI 생태계 조성에 기여합니다.",
      "intent": "fact",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '추론형 AI 데이터는 단순한 학습 자원이 아니라 AI의 사고 체계(Cognitive System)를 형성하는 근본적 요소입니다'와 '품질관리 활동은 AI 준비성(AI Readiness) 향상 및 지속가능한 AI 생태계 조성에 기여합니다'에서 직접 추출",
        "2) 질문 구성 방식 — 데이터의 역할과 품질관리의 기여라는 동일 차원(역할/기여) 내 복수 요소를 묻는 fact 유형으로 구성"
      ],
      "answerable": true
    },
    {
      "q": "데이터 품질 수준이 AI의 어떠한 특성들을 결정합니까?",
      "a": "데이터 품질 수준은 AI의 신뢰성, 안전성, 지속가능한 발전을 결정합니다.",
      "intent": "fact",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '데이터 품질 수준이 AI의 신뢰성, 안전성, 지속가능한 발전을 결정합니다'에서 직접 추출",
        "2) 질문 구성 방식 — 데이터 품질 수준이 결정하는 복수의 AI 특성(신뢰성·안전성·지속가능한 발전)을 하나의 fact 질문으로 구성하여 단순 단일 값 조회를 넘는 깊이 확보"
      ],
      "answerable": true
    },
    {
      "q": "지속가능한 AI 생태계 조성을 위해 구축이 필요한 품질 프레임워크의 기반 표준은 무엇이며, 고품질 데이터 관리 측면에서 요구되는 사항은 무엇입니까?",
      "a": "지속가능한 AI 생태계 조성을 위해 국제 표준인 ISO/IEC 5259 및 EU AI Act 기반의 품질 프레임워크 구축이 필요합니다. 또한 고품질 데이터 확보 및 지속적 관리가 요구됩니다.",
      "intent": "how",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '국제 표준(ISO/IEC 5259, EU AI Act) 기반의 품질 프레임워크 구축이 필요하며'와 '고품질 데이터 확보 및 지속적 관리'에서 직접 추출",
        "2) 질문 구성 방식 — 품질 프레임워크 구축 방법(기반 표준)과 데이터 관리 요건을 묻는 how 유형으로 구성하며, 컨텍스트에 명시된 표준명 및 관리 요건을 모두 포함"
      ],
      "answerable": true
    }
  ]
}

{
  "qa_list": [
    {
      "q": "추론형 AI 데이터 생애주기에서 생성(Generation) 단계의 핵심 활동과 주요 과제는 무엇입니까?",
      "a": "생성(Generation) 단계는 고품질 데이터를 수집·생성하는 단계로, 데이터 수집, 전처리, 라벨링을 포함합니다. AI 데이터 생애주기에서 초기 단계에 해당하며, 노이즈 제거와 다양성 확보가 핵심 과제입니다.",
      "intent": "fact",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '생성(Generation) 단계는 고품질 데이터를 수집·생성하는 단계로, 데이터 수집, 전처리, 라벨링을 포함합니다. AI 데이터 생애 주기에서 초기 단계로, 노이즈 제거와 다양성 확보가 핵심입니다.'에 직접 근거함.",
        "2) 질문 구성 방식 — 단계의 구성 활동(수집·전처리·라벨링)과 핵심 과제(노이즈 제거·다양성 확보)를 동일한 'fact' 차원에서 묻는 단일 차원 질문으로 구성함."
      ],
      "answerable": true
    },
    {
      "q": "추론형 AI 데이터 생애주기에서 검증(Verification) 단계는 어떠한 방식으로 수행됩니까?",
      "a": "검증(Verification) 단계는 생성된 데이터의 논리적 일관성과 정확성을 확인하는 단계입니다. AI 자동화와 인간 검증을 결합하여 편향이나 오류를 탐지하는 방식으로 수행됩니다.",
      "intent": "how",
      "reasoning": [
        "1) 근거 문장/항목 매핑 — '검증(Verification) 단계는 생성된 데이터의 논리적 일관성과 정확성을 확인합니다. AI 자동화와 인간 검증을 결합하여 편향이나 오류를 탐지합니다.'에 직접 근거함.",
        "2) 질문 구성 방식 — 검증 단계의 구체적 수행 방식(AI 자동화 + 인간 검증 결합)과 탐지 대상(편향·오류)을 'how' 차원에서 묻는 질문으로 구성함."
      ],
      "answerable": true
    },
    {
      "q": "추론형 AI 데이터 생애주기에서 정제(Cleansing) 단계와 평가(Evaluation) 단계의 역할과 처리 방식은 어떻게 구분됩니까?",
      "a": "정제(Cleansing) 단계는 불완전하거나 오류 있는 데이터를 수정·제거하는 역할을 하며, 대규모 데이터셋에서 AI가 자동화된 클렌징을 통해 개별 데이터셋 단위의 수정을 처리합니다. 평가(Evaluation) 단계는 데이터의 적합성을 측정하는 역할을 하며, 정확도·편향 점수와 같은 모델 성능 지표를 사용하여 수행됩니다. 즉, 정제 단계는 오류 데이터의 수정·제거에, 평가 단계는 적합성 측정에 각각 초점이 맞춰져 있습니다.",
